challenges.solution:
import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';

const SIGNAL_TEMPLATE = `
  <ul>
    @for (signal of signals; track signal.id) {
      @if (signal.active) {
        <li>{{ signal.id }}: {{ signal.strength }}</li>
      }
    }
  </ul>
`;

@Component({
  selector: 'app-signal-list',
  standalone: true,
  imports: [CommonModule],
  template: SIGNAL_TEMPLATE
})
export class SignalListComponent {
  signals = [
    { id: 'A-1', strength: 82, active: true },
    { id: 'A-2', strength: 15, active: false },
    { id: 'A-3', strength: 67, active: true },
    { id: 'A-4', strength: 91, active: true },
  ];

  get activeCount(): number {
    return this.signals.filter(s => s.active).length;
  }
}

