import { Component } from '@angular/core';

@Component({
  selector: 'app-launch-control',
  standalone: true,
  template: `
    <p>System: {{ locked ? 'LOCKED' : 'READY' }}</p>
    <button [disabled]="!locked" (click)="launch()">Launch</button>
    <button (click)="locked = !locked">Toggle Lock</button>
  `
})
export class LaunchControlComponent {
  locked = true;
  launched = false;

  launch() {
    this.launched = true;
  }
}

