import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-readout',
  standalone: true,
  imports: [CommonModule],
  template: `
    <div [class]="statusClass">
      <span>Temp: {{ temperature | number:'1.1-1' }}&deg;C</span>
      <span>Sync: {{ lastSync | date:'HH:mm' }}</span>
    </div>
  `
})
export class ReadoutComponent {
  temperature = 72;
  lastSync = new Date();

  get statusClass(): string {
    return this.temperature < 80 ? 'status-ok' : 'status-warn';
  }
}
